mapper.sql:
from aiw_ai_model_binding b
where 1 = 1

    and b.scenario_code = #{criteria.scenarioCode}


    and b.model_code = #{criteria.modelCode}


    and b.provider_code = #{criteria.providerCode}


    and b.environment = #{criteria.environment}


    and b.enabled = #{criteria.enabled}

mapper.select:
select *
from aiw_ai_model_binding
where scenario_code = #{scenarioCode}
  and environment = #{environment}
limit 1

select b.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
